      "content": "const problems = require('../../data/problems.json');

class ProblemsService {
  static getProblemById(problemId) {
    return problems.find(p => p.id === problemId) || null;
  }

  static getProblemDetails(problemId) {
    const problem = this.getProblemById(problemId);
    if (!problem) return null;

    // Aggregate component statistics
    const languageCounts = {};
    const statusCounts = {};
    let maxPoints = 0;

    if (problem.components && Array.isArray(problem.components)) {
      for (const comp of problem.components) {
        // Count languages
        if (comp.language) {
          languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
        }

        // Count statuses
        if (comp.status) {
          statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
        }

        // Track max points
        if (typeof comp.points === 'number' && comp.points > maxPoints) {
          maxPoints = comp.points;
        }
      }
    }

    return {
      ...problem,
      componentStats: {
        languageCounts,
        statusCounts,
        maxPoints
      }
    };
  }
}

module.exports = ProblemsService;
